package main

import (
	"flag"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
	"k8s.io/klog/v2"
)

func main() {
	klog.InitFlags(nil)
	flag.Parse()

	port := flag.String("port", "8080", "API port")
	runtimeClassName := flag.String("runtime-class-name", "kuasar-vmm", "Runtime class name")
	enableTLS := flag.Bool("enable-tls", false, "Enable TLS")
	tlsCert := flag.String("tls-cert", "", "TLS cert path")
	tlsKey := flag.String("tls-key", "", "TLS key path")
	enableAuth := flag.Bool("enable-auth", false, "Enable auth")

	config := &workloadmanager.Config{
		Port:             *port,
		RuntimeClassName: *runtimeClassName,
		EnableTLS:        *enableTLS,
		TLSCert:          *tlsCert,
		TLSKey:           *tlsKey,
		EnableAuth:       *enableAuth,
	}

	server, err := workloadmanager.NewServer(config)
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	klog.Infof("Starting workload manager on port %s", config.Port)
	if err := server.RunWithGracefulShutdown(); err != nil {
		klog.Fatalf("Server failed: %v", err)
	}
}

